async function exchangeCodeForTokens({ code, codeVerifier }) {
  const body = new URLSearchParams();
  body.set('grant_type', 'authorization_code');
  body.set('code', code);
  body.set('redirect_uri', OIDC_REDIRECT_URI);
  body.set('client_id', OIDC_CLIENT_ID);
  if (codeVerifier) body.set('code_verifier', codeVerifier);

  const headers = {
    'Content-Type': 'application/x-www-form-urlencoded'
  };

  if (OIDC_CLIENT_SECRET) {
    const basic = Buffer.from(`${OIDC_CLIENT_ID}:${OIDC_CLIENT_SECRET}`).toString('base64');
    headers.Authorization = `Basic ${basic}`;
    body.delete('client_id');
  }

  const resp = await fetch(OIDC_TOKEN_ENDPOINT, {
    method: 'POST',
    headers,
    body
  });

  const text = await resp.text();
  let json;
  try { json = JSON.parse(text); } catch { json = null; }

  if (!resp.ok) {
    const msg = json ? JSON.stringify(json) : text;
    throw new Error(`Token endpoint error (${resp.status}): ${msg}`);
  }

  return json;
}

function escapeHtml(s) {
  return String(s ?? '')
    .replace(/&/g, '&amp;')
    .replace(/</g, '&lt;')
    .replace(/>/g, '&gt;')
    .replace(/"/g, '&quot;')
    .replace(/'/g, '&#039;');
}

